-- 2. Link builder_id by exact builder-name match (same pattern as 0004).
--    Only NULL builder_ids are touched, so this is idempotent and never
--    re-points an existing society. All nine builders already exist in the roster.
UPDATE societies
SET builder_id = (SELECT id FROM builders WHERE builders.name = societies.builder)
WHERE builder_id IS NULL AND TRIM(builder) <> '';

